const fetch = require('node-fetch');
const url = 'https://api.hubapi.com/crm/v3/objects/contacts'
const token = 'YOUR-TOKEN';

const body = {
	"properties": {
	        "email": $email
	}
};

if ($firstname) body.properties.firstname = $firstname;
if ($lastname) body.properties.lastname = $lastname;

const options = {
	method: 'POST',
	headers: {
	        'Authorization': `Bearer ${token}`,
		'Content-Type': 'application/json'
	},
	body: JSON.stringify(body)
};

try {
	const response = await fetch(url, options);
	const text = await response.text();
	return text;
} catch (error) {
	console.error(error);
	return '';
}

const fetch = require('node-fetch');
const baseId = 'YOUR-BASE-ID';
const tableId = 'YOUR-TABLE-ID';
const token = 'YOUR-TOKEN';

const body = {
	"records": [
		{
			"fields": {
				"column1": $column1,
				"column2": $column2,
			}
		}
	]
};

const options = {
	method: 'POST',
	headers: {
		'Authorization': `Bearer ${token}`,
		'Content-Type': 'application/json'
	},
	body: JSON.stringify(body)
};

const url = `https://api.airtable.com/v0/${baseId}/${tableId}`

try {
	const response = await fetch(url, options);
	const text = await response.text();
	return text;
} catch (error) {
	console.error(error);
	return '';
}

const timeZone = 'Australia/Sydney';
const options = {
    timeZone: timeZone,
    year: 'numeric',
    month: 'long',
    day: 'numeric',
    weekday: 'long',
    hour: '2-digit',
    minute: '2-digit',
    second: '2-digit',
    hour12: true
};
const today = new Date();
const formattedDate = today.toLocaleString('en-GB', options);
const result = {
    "formattedDate": formattedDate,
    "timezone": timeZone
};
return JSON.stringify(result);

const fetch = require('node-fetch');
const url = 'https://morning-star.p.rapidapi.com/market/v2/get-movers';
const options = {
	method: 'GET',
	headers: {
		'X-RapidAPI-Key': 'YOUR-API-KEY',
		'X-RapidAPI-Host': 'morning-star.p.rapidapi.com'
	}
};

try {
	const response = await fetch(url, options);
	const result = await response.text();
	console.log(result);
	return result;
} catch (error) {
	console.error(error);
	return '';
}

