/*
* You can use any libraries imported in Flowise
* You can use properties specified in Input Schema as variables. Ex: Property = userid, Variable = $userid
* Must return a string value at the end of function
*/

const fetch = require('node-fetch');
const webhookUrl = 'https://hook.eu1.make.com/abcdefg';
const body = {
	"message": $message
};
const options = {
    method: 'POST',
    headers: {
        'Content-Type': 'application/json'
    },
    body: JSON.stringify(body)
};
try {
    const response = await fetch(webhookUrl, options);
    const text = await response.text();
    return text;
} catch (error) {
    console.error(error);
    return '';
}

const fetch = require('node-fetch');
const apiKey = 'YOUR_PERPLEXITY_API_KEY';  // Put Your Perplexity AI API key here

const query = $query;

const options = {
	method: 'POST',
	headers: {
		'Content-Type': 'application/json',
		'Authorization': 'Bearer <YOUR_PERPLEXITY_API_KEY>'
	},
	body: JSON.stringify({
		model: 'llama-3-sonar-small-32k-online',  // Model
		messages: [
			{
				role: 'system',
				content: 'You are a research assistant.'
			},
			{
				role: 'user',
				content: query
			}
		]
	})
};

try {
	const response = await fetch('https://api.perplexity.ai/chat/completions', options);
	const data = await response.json();
	return JSON.stringify(data);
} catch (error) {
	console.error(error);
	return 'Error occurred while fetching data from Perplexity AI';
}

